from apikit import Client, APIError, UnauthorizedError, ForbiddenError, NotFoundError, ConflictError
status_to_exc = {401: UnauthorizedError, 403: ForbiddenError, 404: NotFoundError, 409: ConflictError}
for status_code, exc_cls in status_to_exc.items():
  with respx.mock:
    respx.get('https://api.example.com/api/v1/user').mock(
      return_value=httpx.Response(status_code, json={'error': {'code': status_code, 'message': 'err'}})
    )
    c = Client('https://api.example.com', api_key='tok')
    raised = None
    try:
      c.get_user()
    except exc_cls as e:
      raised = e
    assert raised is not None
    assert isinstance(raised, APIError)

import dataclasses
from apikit import User, APIKey, Organization, PAT
user_fields = {f.name for f in dataclasses.fields(User)}
assert 'created_at' in user_fields
assert 'provider_id' in user_fields
apikey_fields = {f.name for f in dataclasses.fields(APIKey)}
assert 'key_id' in apikey_fields
pat_fields = {f.name for f in dataclasses.fields(PAT)}
assert 'token_id' in pat_fields

import dataclasses
from apikit import APIKeyWithSecret
fields = {f.name for f in dataclasses.fields(APIKeyWithSecret)}
assert fields == {'key', 'key_id', 'expires_at'}
assert 'created_at' not in fields
assert 'revoked_at' not in fields

property_tests.invariant_check:
for each (base_url, mount_point) pair:
  c = Client(base_url, mount_point=mount_point)
  for path in ['/healthz', '/readyz', '/version', '/user', '/users', '/orgs']:
    if path in ['/healthz', '/readyz', '/version']:
      url = c._base_url + path
    else:
      url = c._base_url + c._mount_point + path
    path_part = url.replace('https://', '').replace('http://', '')
    assert '//' not in path_part

for mount_point in ['/api/v1', '/v2', '/api', '/mount']:
  c = Client('https://api.example.com', mount_point=mount_point)
  for method_url in [c._base_url + '/healthz', c._base_url + '/readyz', c._base_url + '/version']:
    path_after_host = method_url.split('api.example.com')[1]
    assert mount_point not in path_after_host

